"  Future<void> _getUserLocation({bool forceRefresh = false}) async {
    setState(() {
      _loadingLocation = true;
    });
    try {
      bool serviceEnabled = await Geolocator.isLocationServiceEnabled();
      if (!serviceEnabled) {
        setState(() {
          _loadingLocation = false;
        });
        if (mounted) {
          WidgetsBinding.instance.addPostFrameCallback((_) {
            ScaffoldMessenger.of(context).showSnackBar(
              const SnackBar(
                content: Text("Lütfen telefonunuzun konum servisini (GPS) açın."),
                backgroundColor: Colors.redAccent,
              ),
            );
          });
        }
        return;
      }

      LocationPermission permission = await Geolocator.checkPermission();
      if (permission == LocationPermission.denied) {
        permission = await Geolocator.requestPermission();
        if (permission == LocationPermission.denied) {
          setState(() {
            _loadingLocation = false;
          });
          if (mounted) {
            WidgetsBinding.instance.addPostFrameCallback((_) {
              ScaffoldMessenger.of(context).showSnackBar(
                const SnackBar(
                  content: Text("Yakındaki camileri görebilmek için konum izni vermeniz gerekmektedir."),
                  backgroundColor: Colors.orangeAccent,
                ),
              );
            });
          }
          return;
        }
      }

      if (permission == LocationPermission.deniedForever) {
        setState(() {
          _loadingLocation = false;
        });
        if (mounted) {
          WidgetsBinding.instance.addPostFrameCallback((_) {
            ScaffoldMessenger.of(context).showSnackBar(
              const SnackBar(
                content: Text("Konum izni reddedildi. Lütfen ayarlardan izin verin."),
                backgroundColor: Colors.redAccent,
              ),
            );
          });
        }
        return;
      }\
